import{_ as t,o as a,c as r,ae as s}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Fraud Overview","description":"","frontmatter":{"title":"Fraud Overview","slug":"fraud"},"headers":[],"relativePath":"marketer-hub/fraud.md","filePath":"marketer-hub/fraud.md"}'),o={name:"marketer-hub/fraud.md"};function i(d,e,n,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Prevent wasted spend with higher quality data based on a privacy-focused attribution model and a combination of accurate detection and quick, flexible response. Along with industry-standard blocking rules, Branch generates helpful Branch Dashboard views on how well your ad spend is protected.</p><h3 id="fraud-indicators" tabindex="-1">Fraud Indicators <a class="header-anchor" href="#fraud-indicators" aria-label="Permalink to &quot;Fraud Indicators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fraud Indicator</th><th>✔️ Fraud Method</th><th>❌ Detection Strategy</th></tr></thead><tbody><tr><td>Fake Devices/Click Farms</td><td>Use emulators and device farms to generate fraudulent clicks.</td><td><strong>Blacklisted IPs</strong>, because many conversions will come from the same IP address; high click-to-install rates, because this fraud method is most cost-effective when clicks lead to installs</td></tr><tr><td>Install Hijacking/Click Injection</td><td>Use a compromised app already on the device to detect installs, and fire off a click just before the new app is opened.</td><td><strong>Short click-to-install times</strong>, because users typically open apps right after downloading</td></tr><tr><td>Click Flooding</td><td>Generate millions of clicks with random device IDs (IDFA or GAID), and hope that some of those users will install later.</td><td><strong>Long click-to-install times</strong>, because there is no legitimate connection between click and install.</td></tr><tr><td>Ad Stacking</td><td>Layers dozens of ads on top of each other, leading to fraudulent clicks on ads that aren&#39;t visible.</td><td><strong>Low click-to-install rates</strong>, because this fraud method generates excessive numbers of clicks.</td></tr><tr><td>Device Reset</td><td>New devices from suspicious IPs.</td><td><strong>High click to install rates</strong>, because devices can repeatedly reset themselves and keeping an eye on user value metrics.</td></tr></tbody></table><h2 id="how-does-it-work" tabindex="-1">How Does It Work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How Does It Work?&quot;">​</a></h2><p>Branch’s unique, cross-platform scale provides the data depth and breadth required for a resilient, scalable detection model.</p><p>Branch uses constantly advancing proprietary algorithms to dynamically block attributions on browsers and devices showing suspicious behavior across our platform.</p><p>We also automate the detection of statistical variations across a vast pool of data signals to spot and block fraudulent patterns as they emerge.</p>',8)])])}const f=t(o,[["render",i]]);export{p as __pageData,f as default};
